{
 "level": "B1–B2",
 "intro": "In this topic you will learn <strong>Negative Questions</strong> - questions with a negative form that express surprise, surprise or expectation of a certain answer.",
 "rules": [
 {
 "label": "STRUCTURE",
 "color": "emerald",
 "text": "<strong>Negative Form</strong> auxiliary verb:",
 "example": "Don't you know? Isn't she coming?"
 },
 {
 "label": "MEANING",
 "color": "blue",
 "text": "<strong>Surprise</strong> or expectation:",
 "example": "Don't you like coffee? (surprised)"
 },
 {
 "label": "ANSWER",
 "color": "amber",
 "text": "<strong>Yes/No</strong> in content, not in form:",
 "example": "Don't you know? - Yes, I do. / No, I don't."
 }
 ]
}

{
 "title": "1. What are Negative Questions?",
 "intro": "Negative questions are questions with a negative form of the auxiliary verb:",
 "items": [
 {
 "label": "Regular question",
 "title": "Do you know?",
 "subtitle": "Neutral question"
 },
 {
 "label": "Negative question",
 "title": "Don't you know?",
 "subtitle": "Surprise or expectation"
 },
 {
 "label": "Distinction",
 "title": "Emotional subtext",
 "subtitle": "Expresses the attitude of the speaker"
 }
 ]
}

{
 "title": "2. Negative Questions with DO/DOES/DID",
 "sections": [
 {
 "label": "Present Simple",
 "color": "emerald",
 "description": "In Present Simple we use <strong>don't/doesn't</strong>:",
 "examples": [
 {
 "en": "Don't you like coffee?",
 "ua": "Don't you like coffee?"
 },
 {
 "en": "Doesn't she work here?",
 "ua": "Doesn't she work here?"
 },
 {
 "en": "Don't they know the answer?",
 "ua": "Don't they know the answer?"
 },
 {
 "en": "Doesn't he speak English?",
 "ua": "Doesn't he speak English?"
 }
 ]
 },
 {
 "label": "Past Simple",
 "color": "sky",
 "description": "In Past Simple we use <strong>didn't</strong>:",
 "examples": [
 {
 "en": "Didn't you see the movie?",
 "ua": "Didn't you see the movie?"
 },
 {
 "en": "Didn't she call you?",
 "ua": "Didn't she call you?"
 },
 {
 "en": "Didn't they arrive yesterday? ",
 "ua": "Didn't they arrive yesterday? "
 },
 {
 "en": "Didn't it rain last night?",
 "ua": "Didn't it rain last night?"
 }
 ]
 },
 {
 "label": "Key point",
 "color": "purple",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": {
 "en": "Don't/Doesn't/Didn't + Subject + Verb?",
 "ua": "Don't/Doesn't/Didn't + Subject + Verb?"
 },
 "note": "📌 The main verb remains in the base form"
 }
 ]
}

{
 "title": "3. Negative Questions with TO BE",
 "sections": [
 {
 "label": "Present Simple — ISN'T/AREN'T",
 "color": "blue",
 "description": "With <strong>to be</strong> in the Present Simple we use isn't/aren't:",
 "examples": [
 {
 "en": "Isn't she happy?",
 "ua": "Isn't she happy?"
 },
 {
 "en": "Aren't you ready?",
 "ua": "Aren't you ready?"
 },
 {
 "en": "Isn't it expensive?",
 "ua": "Isn't it expensive?"
 },
 {
 "en": "Aren't they at home?",
 "ua": "Aren't they at home?"
 }
 ]
 },
 {
 "label": "Past Simple — WASN'T/WEREN'T",
 "color": "amber",
 "description": "In the Past Simple we use wasn't/weren't:",
 "examples": [
 {
 "en": "Wasn't he at work yesterday? tired?",
 "ua": "Wasn't he at work yesterday? tired?"
 },
 {
 "en": "Weren't you tired?",
 "ua": "Weren't you tired?"
 },
 {
 "en": "Wasn't it difficult?",
 "ua": "Wasn't it difficult?"
 },
 {
 "en": "Weren't they happy?",
 "ua": "Weren't they happy?"
 }
 ]
 },
 {
 "label": "Formal variant",
 "color": "rose",
 "description": "In formal language you can use the full form:",
 "examples": [
 {
 "en": "Is she not happy?",
 "ua": "Is she not happy?"
 },
 {
 "en": "Are you not ready?",
 "ua": "Are you not ready?"
 }
 ],
 "note": "📌 Isn't she? — colloquial, Is she not? - formal"
 }
 ]
}

{
 "title": "4. Negative Questions with modal verbs",
 "sections": [
 {
 "label": "CAN'T / COULDN'T",
 "color": "emerald",
 "description": "With <strong>can/could</strong> we use can't/couldn't:",
 "examples": [
 {
 "en": "Can't you swim?",
 "ua": "Can't you swim?"
 },
 {
 "en": "Couldn't she drive?",
 "ua": "Couldn't she drive?"
 },
 {
 "en": "Can't they help us?",
 "ua": "Can't they help us?"
 }
 ]
 },
 {
 "label": "WON'T / WOULDN'T",
 "color": "sky",
 "description": "With <strong>will/would</strong> we use won't/wouldn't:",
 "examples": [
 {
 "en": "Won't you come?",
 "ua": "Won't you come?"
 },
 {
 "en": "Wouldn't she like it?",
 "ua": "Wouldn't she like it?"
 },
 {
 "en": "Won't they be late?",
 "ua": "Won't they be late?"
 }
 ]
 },
 {
 "label": "SHOULDN'T / MUSTN'T",
 "color": "purple",
 "description": "Other modals can also have a negative form:",
 "examples": [
 {
 "en": "Shouldn't we go?",
 "ua": "Shouldn't we go?"
 },
 {
 "en": "Mustn't I wait? modal + subject + verb",
 "ua": "Mustn't I wait? modal + subject + verb"
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 }
 ]
}

{
 "title": "5. Negative Questions with other tenses",
 "sections": [
 {
 "label": "Present Perfect",
 "color": "blue",
 "description": "In the Present Perfect we use haven't/hasn't:",
 "examples": [
 {
 "en": "Haven't you seen the movie?",
 "ua": "Haven't you seen the movie?"
 },
 {
 "en": "Hasn't she finished not yet? Ving:",
 "ua": "Hasn't she finished not yet? Ving:"
 },
 {
 "en": "Haven't they arrived?",
 "ua": "Haven't they arrived?"
 }
 ]
 },
 {
 "label": "Present Continuous",
 "color": "amber",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Aren't you working now?",
 "ua": "Aren't you working now?"
 },
 {
 "en": "Isn't she coming?",
 "ua": "Isn't she coming?"
 },
 {
 "en": "Aren't they playing?",
 "ua": "Aren't they playing?"
 }
 ]
 },
 {
 "label": "Past Continuous",
 "color": "rose",
 "description": "In the Past Continuous we use wasn't/weren't + Ving:",
 "examples": [
 {
 "en": "Weren't you sleeping?",
 "ua": "Weren't you sleeping?"
 },
 {
 "en": "Wasn't she studying?",
 "ua": "Wasn't she studying?"
 }
 ],
 "note": "📌 Structure: negative form of auxiliary verb + subject + main part"
 }
 ]
}

{
 "title": "6. Meaning and usage of Negative Questions",
 "sections": [
 {
 "label": "Surprise",
 "color": "emerald",
 "description": "Express <strong>surprise</strong> that something is not as expected:",
 "examples": [
 {
 "en": "Don't you like pizza? Everyone likes pizza!",
 "ua": "Don't you like pizza? Everyone likes pizza!"
 },
 {
 "en": "Isn't she coming? I thought she would.",
 "ua": "Isn't she coming? I thought she would."
 }
 ]
 },
 {
 "label": "Waiting for a positive answer",
 "color": "sky",
 "description": "We expect the answer to be yes:",
 "examples": [
 {
 "en": "Didn't you receive my email?",
 "ua": "Didn't you receive my email?"
 },
 {
 "en": "Doesn't he work here?",
 "ua": "Doesn't he work here?"
 }
 ]
 },
 {
 "label": "Polite request or offer",
 "color": "purple",
 "description": "Can sound softer and more polite:",
 "examples": [
 {
 "en": "Won't you have some tea?",
 "ua": "Won't you have some tea?"
 },
 {
 "en": "Won't you sit down?",
 "ua": "Won't you sit down?"
 }
 ]
 },
 {
 "label": "Criticism or sarcasm",
 "color": "rose",
 "description": "Can sound like criticism (depending on the tone):",
 "examples": [
 {
 "en": "Don't you ever listen?",
 "ua": "Don't you ever listen?"
 },
 {
 "en": "Didn't I tell you so?",
 "ua": "Didn't I tell you so?"
 }
 ],
 "note": "⚠️ Intonation and context are very important!"
 }
 ]
}

{
 "title": "7. How to answer Negative Questions",
 "sections": [
 {
 "label": "Answer according to the content",
 "color": "emerald",
 "description": "We answer <strong>Yes/No according to the content</strong>, not according to the form of the question:",
 "examples": [
 {
 "en": "Q: Don't you like coffee? — A: Yes, I do. (I love)",
 "ua": "Q: Don't you like coffee? — A: Yes, I do. (I love)"
 },
 {
 "en": "Q: Don't you like coffee? — A: No, I don't. (I don't like)",
 "ua": "Q: Don't you like coffee? — A: No, I don't. (I don't like)"
 }
 ]
 },
 {
 "label": "Beware of confusion",
 "color": "amber",
 "description": "In some languages, the logic is different, so be careful:",
 "examples": [
 {
 "en": "Don't you know? - Yes, I know. (English)",
 "ua": "Don't you know? - Yes, I know. (English)"
 },
 {
 "en": "Don't you know? - No, I don't know. (English)",
 "ua": "Don't you know? - No, I don't know. (English)"
 }
 ]
 },
 {
 "label": "The full answer is better",
 "color": "sky",
 "description": "For clarity, it is better to give the full answer:",
 "examples": [
 {
 "en": "Q: Isn't she coming? — A: No, she isn't coming.",
 "ua": "Q: Isn't she coming? — A: No, she isn't coming."
 },
 {
 "en": "Q: Don't you like it? A: Yes, I like it very much. Comparison of normal and negative questions",
 "ua": "Q: Don't you like it? A: Yes, I like it very much. Comparison of normal and negative questions"
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 }
 ]
}

{
 "title": "Grammar focus",
 "intro": "Differences between normal and negative questions:",
 "rows": [
 {
 "en": "Positive Question",
 "ua": "Positive Question",
 "note": "Do you like coffee? — a neutral question"
 },
 {
 "en": "Negative Question",
 "ua": "Negative Question",
 "note": "Don't you like coffee? surprise or expectation answers"
 },
 {
 "en": "Emotion",
 "ua": "Emotion",
 "note": "Use the pattern in the examples and focus on the highlighted words."
 },
 {
 "en": "Expectation",
 "ua": "Expectation",
 "note": "Use the pattern in the examples and focus on the highlighted words."
 },
 {
 "en": "Answer",
 "ua": "Answer",
 "note": "Yes/No by the content, not by the form of the question"
 }
 ],
 "warning": "📌 Negative questions express <strong>the attitude of the speaker</strong>, not just ask for a fact"
}

{
 "title": "9. Typical mistakes",
 "items": [
 {
 "label": "Mistake 1",
 "color": "rose",
 "title": "Confusion with the answer (answer according to the form, not the content).",
 "wrong": "❌ Q: Don't you like it? A: Yes, I don't. (wrong)",
 "right": " ✅ <span class=\"font-mono\">Q: Don't you like it? A: No, I don't. / Yes I do. 3"
 },
 {
 "label": "Mistake 2",
 "color": "amber",
 "title": "Grammar focus",
 "wrong": "❌ You don't like coffee?",
 "right": "✅ <span class=\"font-mono\">Don't you like coffee?</span>"
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Incorrect form of the main verb.",
 "wrong": "❌ Doesn't she likes it?",
 "right": "​​​​​​​​ subtext."
 },
 {
 "label": "Mistake 4",
 "color": "purple",
 "title": "Grammar focus",
 "wrong": "❌ Don't you have a pen? (if you're just asking neutrally)",
 "right": " ✅ <span class=\"font-mono\">Do you have a pen? (neutral)</span>"
 }
 ]
}

{
 "title": "11. Practice",
 "select_title": "Exercise 1. Choose the correct form",
 "select_intro": "Choose the correct negative question.",
 "selects": [
 {
 "label": "a) You don't like coffee? / b) Don't you like coffee? / c) Do you don't like coffee?",
 "prompt": "Which form is correct?"
 },
 {
 "label": "a) She isn't happy? / b) Isn't she happy? / c) Is she not happy?",
 "prompt": "What is the colloquial form?"
 },
 {
 "label": "a) Can't you swim? / b) You can't swim? / c) Don't you can swim?",
 "prompt": "What form is correct?"
 }
 ],
 "options": [
 "a",
 "b",
 "c"
 ],
 "input_title": "Exercise 2. Create a negative question negative.",
 "input_intro": "Follow the prompt and write the answer.",
 "inputs": [
 {
 "before": "Do you know? → ",
 "after": ""
 },
 {
 "before": "Is she coming? → ",
 "after": ""
 },
 {
 "before": "Can they help? → ",
 "after": ""
 },
 {
 "before": "Did you see it? → ",
 "after": ""
 }
 ],
 "rephrase_title": "Exercise 3. Correct the error",
 "rephrase_intro": "Find and correct the error in the negative question.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "You don't like coffee?",
 "example_target": "Don't you like coffee?"
 },
 {
 "original": "1. Doesn't she like it?",
 "placeholder": "Fix the error"
 },
 {
 "original": "2. You can't swim?",
 "placeholder": "Fix the error"
 },
 {
 "original": "3. Do you don't know?",
 "placeholder": "Correct the error"
 }
 ]
}

